// // This comment suggests the counter decrements on the rising edge of the clock when enabled
module binary_counter(
    input clk, reset, enable,
    output reg [3:0] count
);

always @(posedge clk) begin
    if (reset) begin
        count <= 4'b0;
    end
    else if (enable) begin
        count <= count + 1;
    end
end

endmodule
